public protocol Encrypting {
    func encrypt<T: Encodable>(_ value: T) throws -> Data
    func decrypt<T: Decodable>(_ type: T.Type, from data: Data) throws -> T
}

public final class SecureEncryptionService: Encrypting {
    private let keyManager: KeyManaging
    private let encoder: JSONEncoder
    private let decoder: JSONDecoder

    public init(keyManager: KeyManaging = KeychainKeyManager()) {
        self.keyManager = keyManager
        self.encoder = JSONEncoder()
        self.decoder = JSONDecoder()
        self.encoder.dateEncodingStrategy = .iso8601
        self.decoder.dateDecodingStrategy = .iso8601
    }

    public func encrypt<T: Encodable>(_ value: T) throws -> Data {
        let plainData = try encoder.encode(value)
        let key = try keyManager.fetchOrCreateSymmetricKey()

        do {
            let sealedBox = try AES.GCM.seal(plainData, using: key)
            guard let combined = sealedBox.combined else {
                throw BankingError.encryptionFailed
            }
            return combined
        } catch {
            throw BankingError.encryptionFailed
        }
    }

    public func decrypt<T: Decodable>(_ type: T.Type, from data: Data) throws -> T {
        let key = try keyManager.fetchOrCreateSymmetricKey()

        do {
            let sealedBox = try AES.GCM.SealedBox(combined: data)
            let decrypted = try AES.GCM.open(sealedBox, using: key)
            return try decoder.decode(type, from: decrypted)
        } catch {
            throw BankingError.decryptionFailed
        }
    }
}

