    }

    public func loadAccounts() throws -> [Account] {
        guard fileManager.fileExists(atPath: fileURL.path) else { return [] }

        do {
            let data = try Data(contentsOf: fileURL)
            return try encryptionService.decrypt([Account].self, from: data)
        } catch {
            throw BankingError.persistenceFailed
        }
    }

    private static func makeFileURL(fileManager: FileManager) -> URL {
        let directory = fileManager.urls(for: .documentDirectory, in: .userDomainMask).first!
        return directory.appendingPathComponent("accounts.secure")
    }

    private func applyFileProtection() throws {
        try fileManager.setAttributes(
            [.protectionKey: FileProtectionType.complete],
            ofItemAtPath: fileURL.path
        )
    }
}

