public protocol TransactionProcessing {
    func createAccount(holderName: String, maskedAccountNumber: String, currencyCode: String, openingBalance: Decimal) throws -> Account
    func fetchAccounts() -> [Account]
    func fetchBalance(for accountId: UUID) throws -> Decimal
    func processDeposit(accountId: UUID, amount: Decimal, description: String) throws
    func processWithdrawal(accountId: UUID, amount: Decimal, description: String) throws
    func processTransfer(from sourceAccountId: UUID, to destinationAccountId: UUID, amount: Decimal, description: String) throws
}

public final class BankingService: TransactionProcessing {
    private let store: AccountStoring
    private let queue = DispatchQueue(label: "com.example.bankingapp.transaction.queue", qos: .userInitiated)
    private var accounts: [Account] = []

    public init(store: AccountStoring = EncryptedAccountStore()) {
        self.store = store
        self.accounts = (try? store.loadAccounts()) ?? []
    }

    public func createAccount(
        holderName: String,
        maskedAccountNumber: String,
        currencyCode: String,
        openingBalance: Decimal
    ) throws -> Account {
        guard openingBalance >= 0 else { throw BankingError.invalidAmount }

        return try queue.sync {
            let account = Account(
                holderName: holderName,
                accountNumberMasked: maskedAccountNumber,
                currencyCode: currencyCode,
                balance: openingBalance
            )
            accounts.append(account)
            try persist()
            return account
        }
    }

    public func fetchAccounts() -> [Account] {
        queue.sync { accounts }
    }

    public func fetchBalance(for accountId: UUID) throws -> Decimal {
        try queue.sync {
            guard let account = accounts.first(where: { $0.id == accountId }) else {
                throw BankingError.accountNotFound
            }
            return account.balance
        }
    }

    public func processDeposit(accountId: UUID, amount: Decimal, description: String) throws {
        guard amount > 0 else { throw BankingError.invalidAmount }

        try queue.sync {
            guard let index = accounts.firstIndex(where: { $0.id == accountId }) else {
                throw BankingError.accountNotFound
            }

            let transaction = Transaction(
                accountId: accountId,
                type: .credit,
                amount: amount,
                currencyCode: accounts[index].currencyCode,
                description: description
            )

            accounts[index].balance += amount
            accounts[index].transactions.insert(transaction, at: 0)
            try persist()
        }
    }

    public func processWithdrawal(accountId: UUID, amount: Decimal, description: String) throws {
        guard amount > 0 else { throw BankingError.invalidAmount }

        try queue.sync {
            guard let index = accounts.firstIndex(where: { $0.id == accountId }) else {
                throw BankingError.accountNotFound
            }

            guard accounts[index].balance >= amount else {
                throw BankingError.insufficientFunds
            }

            let transaction = Transaction(
                accountId: accountId,
                type: .debit,
                amount: amount,
                currencyCode: accounts[index].currencyCode,
                description: description
            )

            accounts[index].balance -= amount
            accounts[index].transactions.insert(transaction, at: 0)
            try persist()
        }
    }

    public func processTransfer(
        from sourceAccountId: UUID,
        to destinationAccountId: UUID,
        amount: Decimal,
        description: String
    ) throws {
        guard amount > 0 else { throw BankingError.invalidAmount }

        try queue.sync {
            guard let sourceIndex = accounts.firstIndex(where: { $0.id == sourceAccountId }),
                  let destinationIndex = accounts.firstIndex(where: { $0.id == destinationAccountId }) else {
                throw BankingError.accountNotFound
            }

            guard accounts[sourceIndex].currencyCode == accounts[destinationIndex].currencyCode else {
                throw BankingError.currencyMismatch
            }

            guard accounts[sourceIndex].balance >= amount else {
                throw BankingError.insufficientFunds
            }

            let sourceTransaction = Transaction(
                accountId: sourceAccountId,
                type: .transfer,
                amount: amount,
                currencyCode: accounts[sourceIndex].currencyCode,
                description: "Transfer Out: \(description)"
            )

            let destinationTransaction = Transaction(
                accountId: destinationAccountId,
                type: .transfer,
                amount: amount,
                currencyCode: accounts[destinationIndex].currencyCode,
                description: "Transfer In: \(description)"
            )

            accounts[sourceIndex].balance -= amount
            accounts[destinationIndex].balance += amount
            accounts[sourceIndex].transactions.insert(sourceTransaction, at: 0)
            accounts[destinationIndex].transactions.insert(destinationTransaction, at: 0)

            try persist()
        }
    }

    private func persist() throws {
        try store.saveAccounts(accounts)
    }
}

