public final class AccountDetailViewController: UIViewController, UITableViewDataSource {
    private let viewModel: AccountDetailViewModel
    private let balanceLabel = UILabel()
    private let tableView = UITableView(frame: .zero, style: .insetGrouped)

    public init(viewModel: AccountDetailViewModel) {
        self.viewModel = viewModel
        super.init(nibName: nil, bundle: nil)
    }

    @available(*, unavailable)
    required init?(coder: NSCoder) {
        nil
    }

    public override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        title = "Account"

        balanceLabel.font = .preferredFont(forTextStyle: .largeTitle)
        balanceLabel.textAlignment = .center
        balanceLabel.text = viewModel.formattedBalance()

        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "TransactionCell")

        let stack = UIStackView(arrangedSubviews: [balanceLabel, tableView])
        stack.axis = .vertical
        stack.spacing = 16
        stack.translatesAutoresizingMaskIntoConstraints = false

        balanceLabel.translatesAutoresizingMaskIntoConstraints = false
        tableView.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(stack)

        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
            stack.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            stack.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            balanceLabel.heightAnchor.constraint(equalToConstant: 60)
        ])
    }

    public func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        viewModel.transactions().count
    }

    public func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let transaction = viewModel.transactions()[indexPath.row]
        let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath)
        var content = cell.defaultContentConfiguration()
        content.text = transaction.description
        content.secondaryText = CurrencyFormatter.string(from: transaction.amount, currencyCode: transaction.currencyCode)
        cell.contentConfiguration = content
        return cell
    }
}

